import sqlite3

def user_login(username, password):
    try:
        # Connect to legacy database
        conn = sqlite3.connect('legacy_database.db')
        cursor = conn.cursor()
        
        # Check if user exists with provided credentials
        cursor.execute("SELECT username, password FROM users WHERE username = ? AND password = ?", 
                      (username, password))
        result = cursor.fetchone()
        
        conn.close()
        
        # Return True if user found, False otherwise
        return result is not None
        
    except Exception as e:
        print(f"Database error: {e}")
        return False

# Example usage
if __name__ == "__main__":
    # Test login
    if user_login("testuser", "testpass"):
        print("Login successful")
    else:
        print("Login failed")